/**
 * Utility class for creating deep link URIs programmatically
 * Useful for push notifications and email campaigns
 */
object DeepLinkBuilder {

    fun buildProfileLink(userId: String): Uri {
        return Uri.parse("myapp://profile/$userId")
    }

    fun buildPaymentConfirmLink(
        orderId: String,
        amount: String,
        currency: String = "USD"
    ): Uri {
        return Uri.Builder()
            .scheme("myapp")
            .authority("")
            .path("payment/confirm")
            .appendQueryParameter("order_id", orderId)
            .appendQueryParameter("amount", amount)
            .appendQueryParameter("currency", currency)
            .build()
    }

    fun buildHomeLink(): Uri {
        return Uri.parse("myapp://")
    }

    /**
     * Creates an intent that can be used in push notification PendingIntents
     */
    fun createDeepLinkIntent(uri: Uri): Intent {
        return Intent(Intent.ACTION_VIEW, uri).apply {
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
    }
}